// Direct Form II Biquad (Butterworth LPF)
// Coefficients: b0, b1, b2 (numerator), a1, a2 (denominator)
// State variables: x1, x2 (delay elements)

typedef struct {
    float b0, b1, b2;
    float a1, a2;
    float x1, x2; // Delay states
} biquad_t;

float biquad_process(biquad_t *filter, float x) {
    // Direct Form II: y[n] = b0*x[n] + b1*x[n-1] + b2*x[n-2] - a1*y[n-1] - a2*y[n-2]
    // Intermediate state: w[n] = x[n] - a1*w[n-1] - a2*w[n-2]
    // Output: y[n] = b0*w[n] + b1*w[n-1] + b2*w[n-2]

    float w = x - filter->a1 * filter->x1 - filter->a2 * filter->x2;
    float y = filter->b0 * w + filter->b1 * filter->x1 + filter->b2 * filter->x2;

    // Update states
    filter->x2 = filter->x1;
    filter->x1 = w;

    return y;
}
