```c
typedef struct {
    float b0, b1, b2; // Numerator coefficients
    float a1, a2;     // Denominator coefficients (a0 assumed 1.0)
    float x1, x2;     // Delayed inputs
    float y1, y2;     // Delayed outputs
} BiquadFilter;

// Initialize with pre-calculated Butterworth coefficients
void init_biquad(BiquadFilter *f, float b0, float b1, float b2, float a1, float a2) {
    f->b0 = b0; f->b1 = b1; f->b2 = b2;
    f->a1 = a1; f->a2 = a2;
    f->x1 = f->x2 = f->y1 = f->y2 = 0.0f;
}

// Process single sample using Direct Form II
float process_biquad(BiquadFilter *f, float x) {
    // w[n] = x[n] - a1*w[n-1] - a2*w[n-2]
    float w = x - f->a1 * f->y1 - f->a2 * f->y2;

    // y[n] = b0*w[n] + b1*w[n-1] + b2*w[n-2]
    float y = f->b0 * w + f->b1 * f->x1 + f->b2 * f->x2;

    // Update delays (Note: In DF-II, x1/x2 store previous w values)
    f->x2 = f->x1;
    f->x1 = w;
    f->y2 = f->y1;
    f->y1 = w; // Store w as y1 for next iteration's a-coeff calculation

    return y;
}
```
*Note: In standard Direct Form II, the internal state is the intermediate variable `w`. The code above updates `x1/x2` to hold previous `w` values and `y1/y2` to hold previous `w` values for the feedback loop, effectively sharing the delay line.*

