#include <stdint.h>
#include <unistd.h>

// BCM2835 Base Address (Raspberry Pi 1/2/3/Zero)
#define BCM2708_PERI_BASE        0x3F000000
#define GPIO_BASE                (BCM2708_PERI_BASE + 0x200000)

// Register Offsets
#define GPFSEL0                  0x00
#define GPSET0                   0x1C
#define GPCLR0                   0x28
#define GPLEV0                   0x34

// GPIO17 Configuration
#define GPIO17                   17
#define GPIO17_SHIFT             (GPIO17 / 10)
#define GPIO17_MASK              (7 << (GPIO17_SHIFT * 3))
#define GPIO17_FUNC              (1 << (GPIO17_SHIFT * 3)) // Function 1: Output

// Memory Map
volatile uint32_t *gpio = (volatile uint32_t *)(GPIO_BASE);

void delay_ms(uint32_t ms) {
    for (volatile uint32_t i = 0; i < ms * 3000; i++);
}

int main(void) {
    // 1. Set GPIO17 to Output (Function 1)
    gpio[GPFSEL0] &= ~GPIO17_MASK;
    gpio[GPFSEL0] |= GPIO17_FUNC;

    while (1) {
        // 2. Set High (LED On)
        gpio[GPSET0] = (1 << (GPIO17 % 32));
        delay_ms(500);

        // 3. Set Low (LED Off)
        gpio[GPCLR0] = (1 << (GPIO17 % 32));
        delay_ms(500);
    }
    return 0;
}
