// Constants
#define SQRT3_OVER_2 0.86602540378f // sqrt(3)/2
#define SQRT2_OVER_2 0.70710678118f // sqrt(2)/2

// Input: Phase currents (Ia, Ib, Ic)
// Output: Stationary alpha/beta currents
void Clarke_Transform(float Ia, float Ib, float Ic, float *Ialpha, float *Ibeta) {
    // 3-phase to 2-phase (abc to alpha-beta)
    // I_alpha = Ia
    // I_beta  = (Ia * 0 + Ib * SQRT3_OVER_2 + Ic * -SQRT3_OVER_2) / SQRT3_OVER_2
    // Simplified for balanced 3-phase (Ia+Ib+Ic=0):
    *Ialpha = Ia;
    *Ibeta = (Ia * 0.0f) + (Ib * SQRT3_OVER_2) + (Ic * -SQRT3_OVER_2);
    *Ibeta /= SQRT3_OVER_2; // Normalize if using 3/2 transform
}

// Input: Stationary currents (Ialpha, Ibeta), Rotor angle (theta)
// Output: Rotating d/q currents
void Park_Transform(float Ialpha, float Ibeta, float theta, float *Id, float *Iq) {
    // 2-phase to rotating frame (alpha-beta to d-q)
    float cos_t = cosf(theta);
