void LowPower_Sleep_RTC_Wakeup(void) {
    // 1. Enable RTC clock (LSE or LSI)
    RCC->APB1ENR1 |= RCC_APB1ENR1_RTCAPBEN; // Enable RTC APB1 clock
    // Ensure LSE is ready (if used)
    while (!(RCC->BDCR & RCC_BDCR_LSERDY));

    // 2. Configure RTC Wakeup Timer (e.g., 1 second)
    RTC->CR &= ~RTC_CR_WUCKSEL; // Select LSE clock
    RTC->WUTR = 0x00000FFF;    // Set wakeup counter (depends on clock freq)
    RTC->CR |= RTC_CR_WUTE;    // Enable Wakeup Timer
    RTC->CR |= RTC_CR_WUCKEN;  // Enable Wakeup Clock

    // 3. Clear Wakeup Flag
    RTC->SCR = RTC_SCR_WUCF;

